sql:
SELECT name
FROM events
ORDER BY name ASC;

SELECT name
FROM events
WHERE event_type = 'conference';

external_knowledge:
- "Ultimate maestro of events" refers to the department with the highest event count and highest average rating; 
- "Orchestrated the most spectacular events" refers to the department with the maximum event count; 
- "Garnering the highest accolades amongst its peers" refers to the department with the maximum average rating; 
- "Among those departments that have held at least one event and received praise" refers to departments with event counts and average ratings above 0.

; High capacity refers to the seating or attendee capacity of the location; 
; Attendance percentage represents the percentage of attendees who actually attended the event out of the total number of registrations; 
; Average rating refers to the average rating given by attendees for events held at each location, on a 1-5 scale.

sql:
SELECT COUNT(registration_id) AS number_of_registrations
FROM registrations
WHERE event_id = 0;
